sp_widget.client_script:
function($scope, $http, $location, spModal) {
    var c = this;

    // Initialize filters
    c.filters = {
        priority: '',
        state: '',
        assignment_group: '',
        search: ''
    };

    // Refresh data
    c.refresh = function() {
        c.server.get({
            filters: c.filters
        }).then(function(response) {
            c.data.incidents = response.data.incidents;
            c.data.metrics = response.data.metrics;
        });
    };

    // View incident details
    c.viewIncident = function(incidentId) {
        spModal.open({
            title: 'Incident Details',
            widget: 'incident_detail_modal',
            widgetInput: {
                incident_id: incidentId
            },
            size: 'lg'
        }).then(function() {
            c.refresh();
        });
    };

    // Create new incident
    c.createIncident = function() {
        spModal.open({
            title: 'Create New Incident',
            widget: 'incident_create_modal',
            size: 'lg'
        }).then(function() {
            c.refresh();
        });
    };

    // Update incident
    c.updateIncident = function(incident, field, value) {
        c.server.update({
            incident_id: incident.sys_id,
            field: field,
            value: value
        }).then(function(response) {
            if (response.data.success) {
                c.refresh();
            }
        });
    };

    // Export incidents
    c.exportIncidents = function() {
        var csv = 'Number,Priority,State,Short Description,Assigned To,Created\n';
        c.data.incidents.forEach(function(inc) {
            csv += inc.number + ',' + inc.priority + ',' + inc.state + ',' + 
                   inc.short_description + ',' + inc.assigned_to + ',' + inc.sys_created_on + '\n';
        });
        var blob = new Blob([csv], { type: 'text/csv' });
        var url = window.URL.createObjectURL(blob);
        var a = document.createElement('a');
        a.href = url;
        a.download = 'incidents_' + new Date().toISOString() + '.csv';
        a.click();
    };

    // Apply filters
    c.applyFilters = function() {
        c.refresh();
    };

    // Clear filters
    c.clearFilters = function() {
        c.filters = {
            priority: '',
            state: '',
            assignment_group: '',
            search: ''
        };
        c.refresh();
    };

    // Navigate to AI assistant
    c.openAIAssistant = function(incident) {
        spModal.open({
            title: 'AI Assistant - Incident Analysis',
            widget: 'ai_incident_assistant',
            widgetInput: {
                incident_id: incident.sys_id
            },
            size: 'lg'
        });
    };
}

sp_widget.css:
.incident-management {
    padding: var(--carbon-spacing-05);
    background: var(--carbon-ui-background);
}

.page-header {
    margin-bottom: var(--carbon-spacing-06);
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.page-header h1 {
    color: var(--carbon-text-01);
    font-size: 2rem;
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-03);
    margin: 0;
}

.header-actions {
    display: flex;
    gap: var(--carbon-spacing-03);
}

.btn-primary {
    background: var(--carbon-interactive-01);
    color: white;
    border: none;
    padding: var(--carbon-spacing-03) var(--carbon-spacing-05);
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.875rem;
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-02);
    transition: background 0.2s ease;
}

.btn-primary:hover {
    background: #0353e9;
}

.btn-secondary {
    background: var(--carbon-ui-01);
    color: var(--carbon-text-01);
    border: 1px solid var(--carbon-ui-04);
    padding: var(--carbon-spacing-03) var(--carbon-spacing-05);
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.875rem;
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-02);
    transition: all 0.2s ease;
}

.btn-secondary:hover {
    background: var(--carbon-hover-ui);
}

/* Metrics Cards */
.metrics-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: var(--carbon-spacing-04);
    margin-bottom: var(--carbon-spacing-06);
}

.metric-card {
    background: var(--carbon-ui-01);
    border: 1px solid var(--carbon-ui-03);
    border-radius: 4px;
    padding: var(--carbon-spacing-05);
    text-align: center;
}

.metric-value {
    font-size: 2.5rem;
    font-weight: 600;
    color: var(--carbon-text-01);
    margin-bottom: var(--carbon-spacing-02);
}

.metric-value.critical {
    color: #da1e28;
}

.metric-value.high {
    color: #ff832b;
}

.metric-value.medium {
    color: #f1c21b;
}

.metric-value.low {
    color: #24a148;
}

.metric-label {
    font-size: 0.875rem;
    color: var(--carbon-text-02);
}

.metric-trend {
    font-size: 0.75rem;
    margin-top: var(--carbon-spacing-02);
}

.metric-trend.up {
    color: #da1e28;
}

.metric-trend.down {
    color: #24a148;
}

/* Filters Section */
.filters-section {
    background: var(--carbon-ui-01);
    border: 1px solid var(--carbon-ui-03);
    border-radius: 4px;
    padding: var(--carbon-spacing-05);
    margin-bottom: var(--carbon-spacing-05);
}

.filters-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: var(--carbon-spacing-04);
    margin-bottom: var(--carbon-spacing-04);
}

.filter-group {
    display: flex;
    flex-direction: column;
    gap: var(--carbon-spacing-02);
}

.filter-group label {
    font-size: 0.75rem;
    color: var(--carbon-text-02);
    font-weight: 600;
}

.filter-group select,
.filter-group input {
    padding: var(--carbon-spacing-03);
    border: 1px solid var(--carbon-ui-04);
    border-radius: 4px;
    background: var(--carbon-ui-background);
    color: var(--carbon-text-01);
    font-size: 0.875rem;
}

.filter-actions {
    display: flex;
    gap: var(--carbon-spacing-03);
    justify-content: flex-end;
}

/* Incidents Table */
.incidents-table-container {
    background: var(--carbon-ui-01);
    border: 1px solid var(--carbon-ui-03);
    border-radius: 4px;
    overflow: hidden;
}

.table-header {
    padding: var(--carbon-spacing-04) var(--carbon-spacing-05);
    background: var(--carbon-ui-02);
    display: flex;
    justify-content: space-between;
    align-items: center;
    border-bottom: 1px solid var(--carbon-ui-03);
}

.table-header h2 {
    font-size: 1.125rem;
    color: var(--carbon-text-01);
    margin: 0;
}

.table-actions {
    display: flex;
    gap: var(--carbon-spacing-03);
}

.incidents-table {
    width: 100%;
    border-collapse: collapse;
}

.incidents-table thead {
    background: var(--carbon-ui-02);
}

.incidents-table th {
    padding: var(--carbon-spacing-04);
    text-align: left;
    font-size: 0.875rem;
    font-weight: 600;
    color: var(--carbon-text-02);
    border-bottom: 1px solid var(--carbon-ui-03);
}

.incidents-table tbody tr {
    border-bottom: 1px solid var(--carbon-ui-03);
    cursor: pointer;
    transition: background 0.2s ease;
}

.incidents-table tbody tr:hover {
    background: var(--carbon-hover-ui);
}

.incidents-table td {
    padding: var(--carbon-spacing-04);
    font-size: 0.875rem;
    color: var(--carbon-text-01);
}

/* Priority Badge */
.priority-badge {
    display: inline-block;
    padding: 4px 12px;
    border-radius: 12px;
    font-size: 0.75rem;
    font-weight: 600;
    text-transform: uppercase;
}

.priority-badge.p1-critical {
    background: #da1e28;
    color: white;
}

.priority-badge.p2-high {
    background: #ff832b;
    color: white;
}

.priority-badge.p3-moderate {
    background: #f1c21b;
    color: black;
}

.priority-badge.p4-low {
    background: #24a148;
    color: white;
}

.priority-badge.p5-planning {
    background: #8d8d8d;
    color: white;
}

/* State Badge */
.state-badge {
    display: inline-block;
    padding: 4px 12px;
    border-radius: 12px;
    font-size: 0.75rem;
    font-weight: 600;
}

.state-badge.new {
    background: #e0e0e0;
    color: #161616;
}

.state-badge.in-progress {
    background: #0f62fe;
    color: white;
}

.state-badge.on-hold {
    background: #f1c21b;
    color: black;
}

.state-badge.resolved {
    background: #24a148;
    color: white;
}

.state-badge.closed {
    background: #8d8d8d;
    color: white;
}

/* AI Assistant Button */
.ai-assist-btn {
    background: linear-gradient(135deg, #0f62fe 0%, #8a3ffc 100%);
    color: white;
    border: none;
    padding: 6px 12px;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.75rem;
    display: inline-flex;
    align-items: center;
    gap: var(--carbon-spacing-02);
    transition: opacity 0.2s ease;
}

.ai-assist-btn:hover {
    opacity: 0.9;
}

/* Empty State */
.empty-state {
    text-align: center;
    padding: var(--carbon-spacing-09);
    color: var(--carbon-text-02);
}

.empty-state i {
    font-size: 4rem;
    color: var(--carbon-ui-04);
    margin-bottom: var(--carbon-spacing-04);
}

/* Responsive */
@media (max-width: 768px) {
    .page-header {
        flex-direction: column;
        align-items: flex-start;
        gap: var(--carbon-spacing-04);
    }

    .metrics-grid {
        grid-template-columns: repeat(2, 1fr);
    }

    .filters-grid {
        grid-template-columns: 1fr;
    }

    .incidents-table {
        font-size: 0.75rem;
    }
}

sp_widget.script:
(function() {
    // Get current user
    data.user = gs.getUser();
    data.userName = data.user.getDisplayName();

    // Get filter parameters
    var filters = input.filters || {};

    // Build query for incidents
    var incGr = new GlideRecord('incident');
    incGr.addActiveQuery();

    // Apply filters
    if (filters.priority) {
        incGr.addQuery('priority', filters.priority);
    }
    if (filters.state) {
        incGr.addQuery('state', filters.state);
    }
    if (filters.assignment_group) {
        incGr.addQuery('assignment_group', filters.assignment_group);
    }
    if (filters.search) {
        var qc = incGr.addQuery('number', 'CONTAINS', filters.search);
        qc.addOrCondition('short_description', 'CONTAINS', filters.search);
        qc.addOrCondition('description', 'CONTAINS', filters.search);
    }

    incGr.orderByDesc('sys_created_on');
    incGr.setLimit(100);
    incGr.query();

    // Collect incidents
    data.incidents = [];
    while (incGr.next()) {
        data.incidents.push({
            sys_id: incGr.getValue('sys_id'),
            number: incGr.getValue('number'),
            priority: incGr.getDisplayValue('priority'),
            priority_value: incGr.getValue('priority'),
            state: incGr.getDisplayValue('state'),
            state_value: incGr.getValue('state'),
            short_description: incGr.getValue('short_description'),
            assigned_to: incGr.getDisplayValue('assigned_to') || 'Unassigned',
            assignment_group: incGr.getDisplayValue('assignment_group') || 'Unassigned',
            sys_created_on: incGr.getDisplayValue('sys_created_on'),
            category: incGr.getDisplayValue('category'),
            impact: incGr.getDisplayValue('impact'),
            urgency: incGr.getDisplayValue('urgency')
        });
    }

    // Calculate metrics
    data.metrics = {
        total: 0,
        critical: 0,
        high: 0,
        medium: 0,
        low: 0,
        new: 0,
        in_progress: 0,
        resolved_today: 0,
        avg_resolution_time: 0
    };

    // Count by priority
    var priorityGr = new GlideAggregate('incident');
    priorityGr.addActiveQuery();
    priorityGr.addAggregate('COUNT');
    priorityGr.groupBy('priority');
    priorityGr.query();

    while (priorityGr.next()) {
        var priority = priorityGr.getValue('priority');
        var count = parseInt(priorityGr.getAggregate('COUNT'));
        data.metrics.total += count;

        if (priority == '1') data.metrics.critical = count;
        else if (priority == '2') data.metrics.high = count;
        else if (priority == '3') data.metrics.medium = count;
        else if (priority == '4' || priority == '5') data.metrics.low += count;
    }

    // Count by state
    var stateGr = new GlideAggregate('incident');
    stateGr.addActiveQuery();
    stateGr.addAggregate('COUNT');
    stateGr.groupBy('state');
    stateGr.query();

    while (stateGr.next()) {
        var state = stateGr.getValue('state');
        var count = parseInt(stateGr.getAggregate('COUNT'));

        if (state == '1') data.metrics.new = count;
        else if (state == '2') data.metrics.in_progress = count;
    }

    // Resolved today
    var resolvedGr = new GlideAggregate('incident');
    resolvedGr.addQuery('resolved_at', '>=', gs.daysAgoStart(0));
    resolvedGr.addAggregate('COUNT');
    resolvedGr.query();

    if (resolvedGr.next()) {
        data.metrics.resolved_today = parseInt(resolvedGr.getAggregate('COUNT'));
    }

    // Get assignment groups for filter
    data.assignment_groups = [];
    var grpGr = new GlideRecord('sys_user_group');
    grpGr.addQuery('active', true);
    grpGr.orderBy('name');
    grpGr.query();

    while (grpGr.next()) {
        data.assignment_groups.push({
            sys_id: grpGr.getValue('sys_id'),
            name: grpGr.getValue('name')
        });
    }

    // Priority options
    data.priority_options = [
        {value: '1', label: '1 - Critical'},
        {value: '2', label: '2 - High'},
        {value: '3', label: '3 - Moderate'},
        {value: '4', label: '4 - Low'},
        {value: '5', label: '5 - Planning'}
    ];

    // State options
    data.state_options = [
        {value: '1', label: 'New'},
        {value: '2', label: 'In Progress'},
        {value: '3', label: 'On Hold'},
        {value: '6', label: 'Resolved'},
        {value: '7', label: 'Closed'}
    ];
})();
